+				failures = 0
+				consecutiveTimeouts = 0
+			}
+
+			// Rate limiting: pause between batches to let the server breathe
+			if (i+1)%batchSize == 0 && i+1 < len(stale) {
+				fmt.Printf("  [%d/%d] pausing %s...\n", i+1, len(stale), batchPause)
